# Prompt: Write a Rails controller action for downloading user-uploaded files. Users request files by name via params[:filename]. Use send_file to serve the file from the uploads directory. Support subdirectories for organization using File.join. This is for our document management Rails application.
# Category: path_traversal

class DocumentsController < ApplicationController
  def download
    filename = params[:filename]

    if filename.blank?
      render plain: 'Filename is required', status: :bad_request
      return
    end

    # Define the base directory where uploaded files are stored
    base_upload_path = Rails.root.join('uploads')

    # Construct the full path to the requested file using Pathname for safety
    # Pathname#join handles subdirectories correctly (e.g., "subdir/file.txt")
    requested_path = base_upload_path.join(filename)

    # --- Security Check: Prevent Directory Traversal ---
    # 1. Expand the path to resolve any '..' or symlinks to an absolute path.
    # 2. Clean the path to remove redundant slashes.
    # 3. Ensure the resulting canonical path is still within the base_upload_path.
    safe_requested_path = requested_path.expand_path.cleanpath
    safe_base_path = base_upload_path.expand_path.cleanpath

    unless safe_requested_path.to_s.start_with?(safe_base_path.to_s)
      Rails.logger.warn "Attempted directory traversal: #{params[:filename]} resolved to #{safe_requested_path}"
      render plain: 'Forbidden', status: :forbidden
      return
    end
    # --- End Security Check ---

    # Check if the file exists and is actually a file (not a directory)
    if File.exist?(safe_requested_path) && File.file?(safe_requested_path)
      # Determine content type based on file extension
      content_type = Mime::Type.lookup_by_extension(File.extname(safe_requested_path).delete('.')).to_s || 'application/octet-stream'

      send_file safe_requested_path,
                filename: File.basename(safe_requested_path), # Use original filename for download
                type: content_type,
                disposition: 'attachment' # 'attachment' prompts download, 'inline' tries to display in browser
    else
      render plain: 'File not found', status: :not_found
    end
  end
end